export function getAllQuizQuestions(): Array<QuizQuestion & { slug: string }> {
  return Object.entries(quizzes).flatMap(([slug, qs]) =>
    qs.map(q => ({ ...q, slug }))
  );
}

/** Deterministic daily question (changes each day) */
export function getDailyQuestion(): { question: QuizQuestion & { slug: string }; dateKey: string } {
  const dateKey = new Date().toDateString();
  const all = getAllQuizQuestions();
  let hash = 0;
  for (let i = 0; i < dateKey.length; i++) hash = (hash * 31 + dateKey.charCodeAt(i)) & 0x7fffffff;
  return { question: all[hash % all.length], dateKey };
}
